SELECT id, product_id, name, subtitle, main_image, category, tags,
           status, price, version, is_deleted, create_time, update_time
FROM `product`

        is_deleted = 0

                AND status = #{status}


                AND category = #{category}


                AND (name LIKE CONCAT('%', #{keyword}, '%') OR product_id LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY update_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM `product`

        is_deleted = 0

                AND status = #{status}


                AND category = #{category}


                AND (name LIKE CONCAT('%', #{keyword}, '%') OR product_id LIKE CONCAT('%', #{keyword}, '%'))
